+        try await services.snapshots.getUIAutomationSnapshot(snapshotId: snapshotId)
     } else {
+        nil as UIAutomationSnapshot?
+    }
+
+    let targetRequest = FocusTargetResolver.resolve(
+        windowID: windowID,
